package main

import (
	"fmt"
	"strings"
)

// Simulate the bug
func inferTargetFilesFromIssue(title, description string) []string {
	text := title + " " + description
	var files []string

	// Simple file path matching (Pattern 1 from actual code)
	words := strings.Fields(text)
	for _, word := range words {
		if strings.Contains(word, "/") && strings.Contains(word, ".go") {
			files = append(files, word)
		}
	}
	return files
}

func checkExtractionNeeded_OLD(title string) bool {
	// OLD version - no guard
	files := inferTargetFilesFromIssue(title, "")
	return len(files) > 0
}

func checkExtractionNeeded_NEW(title string) bool {
	// NEW version - with guard
	if strings.HasPrefix(title, "Extract ") {
		return false
	}
	files := inferTargetFilesFromIssue(title, "")
	return len(files) > 0
}

func main() {
	// Test cases
	regularIssue := "Add feature to cmd/orch/spawn_cmd.go"
	extractionIssue := "Extract spawn flags phase 1: --mode from cmd/orch/spawn_cmd.go into pkg/orch/. Pure structural extraction — no behavior changes."

	fmt.Println("Regular issue:")
	fmt.Printf("  OLD: %v\n", checkExtractionNeeded_OLD(regularIssue))
	fmt.Printf("  NEW: %v\n", checkExtractionNeeded_NEW(regularIssue))

	fmt.Println("\nExtraction issue:")
	fmt.Printf("  OLD: %v (BUG: triggers recursion!)\n", checkExtractionNeeded_OLD(extractionIssue))
	fmt.Printf("  NEW: %v (FIXED: no recursion)\n", checkExtractionNeeded_NEW(extractionIssue))
}
EOF
